(() => {
  const content = $json.content?.[0]?.text;
  if (!content) return { error: 'No response from attribution engine' };
  try {
    const cleaned = content.replace(/```json|```/g, '').trim();
    const match = cleaned.match(/\{[\s\S]*\}/);
    return match ? JSON.parse(match[0]) : { error: 'Invalid JSON from attribution engine', raw: content.substring(0, 200) };
  } catch (e) {
    return { error: 'Invalid JSON from attribution engine', raw: content.substring(0, 200) };
  }
})()
}}
